+    end;
+
+    local procedure CreateAutomaticAccGroupWithTwoLinesAndBalanceLine(GLAccountNo1: Code[20]; GLAccountNo2: Code[20]; GLAccountNo3: Code[20]): Code[10]
+    var
+        AutomaticAccountHeader: Record "Automatic Account Header";
